{
  "sentences": [
    {
      "text": "我坐公車去公司上班。",
      "pinyin": "Wǒ zuò gōngchē qù gōngsī shàngbān.",
      "pinyin_numeric": "wo3 zuo4 gong1che1 qu4 gong1si1 shang4ban1.",
      "translation_en": "I take the bus to go to work at the company.",
      "translation_ko": "저는 버스를 타고 회사에 출근합니다."
    },
    {
      "text": "他坐捷運去台北車站。",
      "pinyin": "Tā zuò jiéyùn qù Táiběi chēzhàn.",
      "pinyin_numeric": "ta1 zuo4 jie2yun4 qu4 Tai2bei3 che1zhan4.",
      "translation_en": "He takes the MRT to Taipei Main Station.",
      "translation_ko": "그는 지하철을 타고 타이베이 역에 갑니다."
    },
    {
      "text": "我們坐計程車去餐廳吃飯。",
      "pinyin": "Wǒmen zuò jìchéngchē qù cāntīng chīfàn.",
      "pinyin_numeric": "wo3men zuo4 ji4cheng2che1 qu4 can1ting1 chi1fan4.",
      "translation_en": "We take a taxi to the restaurant to eat.",
      "translation_ko": "우리는 택시를 타고 식당에 가서 밥을 먹습니다."
    },
    {
      "text": "你坐公車去哪裡？",
      "pinyin": "Nǐ zuò gōngchē qù nǎlǐ?",
      "pinyin_numeric": "ni3 zuo4 gong1che1 qu4 na3li3?",
      "translation_en": "Where are you going by bus?",
      "translation_ko": "버스를 타고 어디에 가나요?"
    },
    {
      "text": "她坐捷運去學校上課。",
      "pinyin": "Tā zuò jiéyùn qù xuéxiào shàngkè.",
      "pinyin_numeric": "ta1 zuo4 jie2yun4 qu4 xue2xiao4 shang4ke4.",
      "translation_en": "She takes the MRT to school for class.",
      "translation_ko": "그녀는 지하철을 타고 학교에 가서 수업을 듣습니다."
    },
    {
      "text": "我們坐計程車去醫院看朋友。",
      "pinyin": "Wǒmen zuò jìchéngchē qù yīyuàn kàn péngyǒu.",
      "pinyin_numeric": "wo3men zuo4 ji4cheng2che1 qu4 yi1yuan4 kan4 peng2you3.",
      "translation_en": "We take a taxi to the hospital to visit a friend.",
      "translation_ko": "우리는 택시를 타고 병원에 가서 친구를 봅니다."
    },
    {
      "text": "他坐公車去公園散步。",
      "pinyin": "Tā zuò gōngchē qù gōngyuán sànbù.",
      "pinyin_numeric": "ta1 zuo4 gong1che1 qu4 gong1yuan2 san4bu4.",
      "translation_en": "He takes the bus to the park for a walk.",
      "translation_ko": "그는 버스를 타고 공원에 가서 산책합니다."
    },
    {
      "text": "我坐捷運去圖書館看書。",
      "pinyin": "Wǒ zuò jiéyùn qù túshūguǎn kànshū.",
      "pinyin_numeric": "wo3 zuo4 jie2yun4 qu4 tu2shu1guan3 kan4shu1.",
      "translation_en": "I take the MRT to the library to read.",
      "translation_ko": "저는 지하철을 타고 도서관에 가서 책을 봅니다."
    },
    {
      "text": "你坐計程車去車站嗎？",
      "pinyin": "Nǐ zuò jìchéngchē qù chēzhàn ma?",
      "pinyin_numeric": "ni3 zuo4 ji4cheng2che1 qu4 che1zhan4 ma0?",
      "translation_en": "Are you taking a taxi to the station?",
      "translation_ko": "택시를 타고 역에 가나요?"
    },
    {
      "text": "她坐公車去商店買東西。",
      "pinyin": "Tā zuò gōngchē qù shāngdiàn mǎi dōngxī.",
      "pinyin_numeric": "ta1 zuo4 gong1che1 qu4 shang1dian4 mai3 dong1xi1.",
      "translation_en": "She takes the bus to the store to buy things.",
      "translation_ko": "그녀는 버스를 타고 가게에 가서 물건을 삽니다."
    }
  ]
}
